package com.example.webviewwrapper

import android.Manifest
import android.app.Activity
import android.content.Intent
import android.content.pm.PackageManager
import android.graphics.Bitmap
import android.net.Uri
import android.os.Build
import android.os.Bundle
import android.provider.MediaStore
import android.webkit.*
import android.widget.Toast
import androidx.activity.result.contract.ActivityResultContracts
import androidx.appcompat.app.AppCompatActivity
import androidx.core.app.ActivityCompat
import androidx.core.content.ContextCompat
import androidx.core.content.FileProvider
import com.google.firebase.messaging.FirebaseMessaging
import java.io.File
import java.io.FileOutputStream
import java.text.SimpleDateFormat
import java.util.*

class MainActivity : AppCompatActivity() {
    private lateinit var webView: WebView
    private var filePathCallback: ValueCallback<Array<Uri>>? = null
    private var cameraPhotoPath: String? = null

    private val fileChooserLauncher = registerForActivityResult(
        ActivityResultContracts.StartActivityForResult()
    ) { result ->
        if (result.resultCode == Activity.RESULT_OK) {
            val results = mutableListOf<Uri>()
            result.data?.data?.let { results.add(it) }
            if (results.isEmpty() && cameraPhotoPath != null) {
                File(cameraPhotoPath!!).let { file ->
                    if (file.exists()) {
                        results.add(Uri.fromFile(file))
                    }
                }
            }
            filePathCallback?.onReceiveValue(results.toTypedArray())
        } else {
            filePathCallback?.onReceiveValue(null)
        }
        filePathCallback = null
        cameraPhotoPath = null
    }

    private val cameraPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            webView.evaluateJavascript("window.onCameraPermissionGranted && window.onCameraPermissionGranted()", null)
        } else {
            webView.evaluateJavascript("window.onCameraPermissionDenied && window.onCameraPermissionDenied()", null)
        }
    }

    private val notificationPermissionLauncher = registerForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        if (isGranted) {
            FirebaseMessaging.getInstance().token.addOnCompleteListener { task ->
                if (task.isSuccessful) {
                    val token = task.result
                    webView.evaluateJavascript("window.onPushTokenReceived && window.onPushTokenReceived('$token')", null)
                }
            }
        } else {
            webView.evaluateJavascript("window.onPushPermissionDenied && window.onPushPermissionDenied()", null)
        }
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        webView = WebView(this)
        setContentView(webView)

        setupWebView()
    }

    private fun setupWebView() {
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = true
            allowFileAccess = true
            allowContentAccess = true
            setSupportZoom(true)
            builtInZoomControls = false
            loadWithOverviewMode = true
            useWideViewPort = true
            javaScriptCanOpenWindowsAutomatically = true
            mediaPlaybackRequiresUserGesture = false
            mixedContentMode = WebSettings.MIXED_CONTENT_ALWAYS_ALLOW
        }

        webView.addJavascriptInterface(NativeBridge(), "NativeBridge")

        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(view: WebView?, request: WebResourceRequest?): Boolean {
                return false
            }

            override fun onPageStarted(view: WebView?, url: String?, favicon: Bitmap?) {
                super.onPageStarted(view, url, favicon)
            }

            override fun onPageFinished(view: WebView?, url: String?) {
                super.onPageFinished(view, url)
            }
        }

        webView.webChromeClient = object : WebChromeClient() {
            override fun onShowFileChooser(
                webView: WebView?,
                filePathCallback: ValueCallback<Array<Uri>>?,
                fileChooserParams: FileChooserParams?
            ): Boolean {
                this@MainActivity.filePathCallback?.onReceiveValue(null)
                this@MainActivity.filePathCallback = filePathCallback

                val takePictureIntent = Intent(MediaStore.ACTION_IMAGE_CAPTURE)
                if (takePictureIntent.resolveActivity(packageManager) != null) {
                    val photoFile = createImageFile()
                    photoFile?.let {
                        cameraPhotoPath = it.absolutePath
                        val photoURI = FileProvider.getUriForFile(
                            this@MainActivity,
                            "${applicationContext.packageName}.fileprovider",
                            it
                        )
                        takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, photoURI)
                    }
                }

                val contentSelectionIntent = Intent(Intent.ACTION_GET_CONTENT)
                contentSelectionIntent.addCategory(Intent.CATEGORY_OPENABLE)
                contentSelectionIntent.type = "*/*"

                val intentArray = arrayOf(takePictureIntent)

                val chooserIntent = Intent(Intent.ACTION_CHOOSER)
                chooserIntent.putExtra(Intent.EXTRA_INTENT, contentSelectionIntent)
                chooserIntent.putExtra(Intent.EXTRA_TITLE, "Choose File")
                chooserIntent.putExtra(Intent.EXTRA_INITIAL_INTENTS, intentArray)

                fileChooserLauncher.launch(chooserIntent)
                return true
            }

            override fun onPermissionRequest(request: PermissionRequest?) {
                request?.grant(request.resources)
            }

            override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
                consoleMessage?.let {
                    android.util.Log.d("WebView", "${it.message()} -- From line ${it.lineNumber()} of ${it.sourceId()}")
                }
                return true
            }
        }

        webView.loadUrl("https://your-web-app-url.com")
    }

    private fun createImageFile(): File? {
        val timeStamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.getDefault()).format(Date())
        val imageFileName = "JPEG_${timeStamp}_"
        val storageDir = getExternalFilesDir(null)
        return File.createTempFile(imageFileName, ".jpg", storageDir)
    }

    inner class NativeBridge {
        @JavascriptInterface
        fun requestCameraPermission() {
            runOnUiThread {
                if (ContextCompat.checkSelfPermission(this@MainActivity, Manifest.permission.CAMERA)
                    == PackageManager.PERMISSION_GRANTED) {
                    webView.evaluateJavascript("window.onCameraPermissionGranted && window.onCameraPermissionGranted()", null)
                } else {
                    cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
                }
            }
        }

        @JavascriptInterface
        fun openCamera(callbackName: String) {
            runOnUiThread {
                if (ContextCompat.checkSelfPermission(this@MainActivity, Manifest.permission.CAMERA)
                    != PackageManager.PERMISSION_GRANTED) {
                    webView.evaluateJavascript("$callbackName(null, 'Permission denied')", null)
                    return@runOnUiThread
                }

                val takePictureIntent = Intent(MediaStore.ACTION_IMAGE_CAPTURE)
                if (takePictureIntent.resolveActivity(packageManager) != null) {
                    val photoFile = createImageFile()
                    photoFile?.let {
                        val photoURI = FileProvider.getUriForFile(
                            this@MainActivity,
                            "${applicationContext.packageName}.fileprovider",
                            it
                        )
                        takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, photoURI)
                        
                        val launcher = registerForActivityResult(
                            ActivityResultContracts.StartActivityForResult()
                        ) { result ->
                            if (result.resultCode == Activity.RESULT_OK) {
                                webView.evaluateJavascript("$callbackName('$photoURI', null)", null)
                            } else {
                                webView.evaluateJavascript("$callbackName(null, 'Cancelled')", null)
                            }
                        }
                        launcher.launch(takePictureIntent)
                    }
                }
            }
        }

        @JavascriptInterface
        fun saveToLocalStorage(key: String, value: String) {
            val sharedPreferences = getSharedPreferences("WebViewStorage", MODE_PRIVATE)
            sharedPreferences.edit().putString(key, value).apply()
        }

        @JavascriptInterface
        fun getFromLocalStorage(key: String): String? {
            val sharedPreferences = getSharedPreferences("WebViewStorage", MODE_PRIVATE)
            return sharedPreferences.getString(key, null)
        }

        @JavascriptInterface
        fun removeFromLocalStorage(key: String) {
            val sharedPreferences = getSharedPreferences("WebViewStorage", MODE_PRIVATE)
            sharedPreferences.edit().remove(key).apply()
        }

        @JavascriptInterface
        fun clearLocalStorage() {
            val sharedPreferences = getSharedPreferences("WebViewStorage", MODE_PRIVATE)
            sharedPreferences.edit().clear().apply()
        }

        @JavascriptInterface
        fun requestPushNotificationPermission() {
            runOnUiThread {
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                    if (ContextCompat.checkSelfPermission(this@MainActivity, Manifest.permission.POST_NOTIFICATIONS)
                        == PackageManager.PERMISSION_GRANTED) {
                        FirebaseMessaging.getInstance().token.addOnCompleteListener { task ->
                            if (task.isSuccessful) {
                                val token = task.result
                                webView.evaluateJavascript("window.onPushTokenReceived && window.onPushTokenReceived('$token')", null)
                            }
                        }
                    } else {
                        notificationPermissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
                    }
                } else {
                    FirebaseMessaging.getInstance().token.addOnCompleteListener { task ->
                        if (task.isSuccessful) {
                            val token = task.result
                            webView.evaluateJavascript("window.onPushTokenReceived && window.onPushTokenReceived('$token')", null)
                        }
                    }
                }
            }
        }

        @JavascriptInterface
        fun getPushToken(callbackName: String) {
            runOnUiThread {
                FirebaseMessaging.getInstance().token.addOnCompleteListener { task ->
                    if (task.isSuccessful) {
                        val token = task.result
                        webView.evaluateJavascript("$callbackName('$token', null)", null)
                    } else {
                        webView.evaluateJavascript("$callbackName(null, 'Failed to get token')", null)
                    }
                }
            }
        }

        @JavascriptInterface
        fun showToast(message: String) {
            runOnUiThread {
                Toast.makeText(this@MainActivity, message, Toast.LENGTH_SHORT).show()
            }
        }

        @JavascriptInterface
        fun getDeviceInfo(): String {
            val info = mapOf(
                "platform" to "Android",
                "version" to Build.VERSION.RELEASE,
                "model" to Build.MODEL,
                "manufacturer" to Build.MANUFACTURER,
                "sdk" to Build.VERSION.SDK_INT.toString()
            )
            return info.entries.joinToString(",") { "\"${it.key}\":\"${it.value}\"" }.let { "{$it}" }
        }

        @JavascriptInterface
        fun shareContent(title: String, text: String, url: String) {
            runOnUiThread {
                val shareIntent = Intent().apply {
                    action = Intent.ACTION_SEND
                    type = "text/plain"
                    putExtra(Intent.EXTRA_SUBJECT, title)
                    putExtra(Intent.EXTRA_TEXT, "$text\n$url")
                }
                startActivity(Intent.createChooser(shareIntent, "Share via"))
            }
        }

        @JavascriptInterface
        fun vibrate(duration: Long) {
            runOnUiThread {
                val vibrator = getSystemService(VIBRATOR_SERVICE) as android.os.Vibrator
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                    vibrator.vibrate(android.os.VibrationEffect.createOneShot(duration, android.os.VibrationEffect.DEFAULT_AMPLITUDE))
                } else {
                    @Suppress("DEPRECATION")
                    vibrator.vibrate(duration)
                }
            }
        }

        @JavascriptInterface
        fun openExternalUrl(url: String) {
            runOnUiThread {
                val intent = Intent(Intent.ACTION_VIEW, Uri.parse(url))
                startActivity(intent)
            }
        }

        @JavascriptInterface
        fun getNetworkStatus(): String {
            val connectivityManager = getSystemService(CONNECTIVITY_SERVICE) as android.net.ConnectivityManager
            val activeNetwork = connectivityManager.activeNetworkInfo
            val isConnected = activeNetwork?.isConnectedOrConnecting == true
            val type = when (activeNetwork?.type) {
                android.net.ConnectivityManager.TYPE_WIFI -> "wifi"
                android.net.ConnectivityManager.TYPE_MOBILE -> "cellular"
                else -> "unknown"
            }
            return "{\"connected\":$isConnected,\"type\":\"$type\"}"
        }

        @JavascriptInterface
        fun saveFile(base64Data: String, fileName: String, callbackName: String) {
            runOnUiThread {
                try {
                    val data = android.util.Base64.decode(base64Data, android.util.Base64.DEFAULT)
                    val file = File(getExternalFilesDir(null), fileName)
                    FileOutputStream(file).use { it.write(data) }
                    webView.evaluateJavascript("$callbackName('${file.absolutePath}', null)", null)
                } catch (e: Exception) {
                    webView.evaluateJavascript("$callbackName(null, '${e.message}')", null)
                }
            }
        }

        @JavascriptInterface
        fun readFile(filePath: String, callbackName: String) {
            runOnUiThread {
                try {
                    val file = File(filePath)
                    val bytes = file.readBytes()
                    val base64 = android.util.Base64.encodeToString(bytes, android.util.Base64.NO_WRAP)
                    webView.evaluateJavascript("$callbackName('$base64', null)", null)
                } catch (e: Exception) {
                    webView.evaluateJavascript("$callbackName(null, '${e.message}')", null)
                }
            }
        }
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }